#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a:b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false)
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
		a=a*a;
		b>>=1;
	}
	return ans;
}
int ds(int n,int b)
{
	int s=0;
	wh(n)
	{
		s+=n%b;
		n/=b;
	}
	return s;
}
int t,n,x,ok,l,m;
signed main(void)
{
	IOS;
	cin>>t;
	wh(t--)
	{
		cin>>n>>x;
		if(x==1)
		{
			if((n&(n-1))==0)cout<<"Yes\n";
			else cout<<"No\n";
			continue;
		}
		ok=0;
		m=x-1;
		int s=ds(n,x);
		for(l=1;l<=n;l<<=1)
		{
			if(n%m==l%m&&s<=l)
			{
				ok=1;
				break;
			}
		}
		if(ok)cout<<"Yes\n";
		else cout<<"No\n";
	}
	return false;
}
